import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';
import { Link } from 'react-router-dom';

// ... 前面 import 保持不變

const Home = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);

  useEffect(() => {
    const fetchTours = async () => {
      try {
        // 確保路徑與後端一致
        const res = await axiosInstance.get('/api/tours'); 
        setTours(res.data);
      } catch (err) { console.error("抓取失敗:", err); }
    };
    fetchTours();
  }, []);

  return (
    <div className="max-w-[420px] mx-auto bg-white min-h-screen flex flex-col font-sans">
      {/* ... Header 保持不變 ... */}

      {/* Order List Card */}
      <div className="px-6 mb-8">
        <div className="bg-white border border-gray-50 p-6 rounded-[28px] shadow-sm flex items-center">
          <div className="w-14 h-14 bg-yellow-50 rounded-2xl flex items-center justify-center text-2xl mr-4 shadow-inner">
            📋
          </div>
          <div>
            <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest leading-none">Order List</p>
            {/* 這裡目前維持 0 是對的，因為你說還沒做客戶端 */}
            <p className="text-3xl font-black text-gray-900 mt-1">0</p>
          </div>
        </div>
      </div>

      {/* View Package List */}
      <div className="px-6 flex-1 overflow-y-auto">
        <div className="flex justify-between items-center mb-5 px-1">
          <h3 className="font-bold text-gray-800 text-base">View Package</h3>
          <span className="text-[10px] text-gray-400 bg-gray-100 px-2 py-1 rounded-md">{tours.length} items</span>
        </div>

        <div className="space-y-6 pb-24"> {/* 加上 pb 避免被底部按鈕遮住 */}
          {tours.length > 0 ? (
            tours.map(tour => (
              <div key={tour._id} className="flex space-x-4 items-center">
                <div className="w-24 h-24 rounded-[24px] overflow-hidden shadow-sm bg-gray-50 flex-shrink-0">
                  {/* 🔴 這裡一定要加上 tour.imageUrl 的判斷 */}
                  <img 
                    src={tour.imageUrl || "https://via.placeholder.com/150?text=No+Image"} 
                    className="w-full h-full object-cover" 
                    alt={tour.title} 
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="font-bold text-gray-800 text-[15px] truncate">{tour.title}</h4>
                  <p className="text-gray-400 text-[11px] font-bold mt-1 uppercase truncate">{tour.location || 'Australia'}</p>
                  <div className="mt-3">
                    <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black shadow-sm ${tour.status === 'Available' ? 'bg-[#ADFF2F] text-green-900' : 'bg-red-500 text-white'}`}>
                      {tour.status === 'Available' ? `AUD ${tour.price}` : 'SOLD OUT'}
                    </span>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <p className="text-center text-gray-300 text-sm mt-10">No packages found.</p>
          )}
        </div>
      </div>

      {/* Bottom Button - 修正名稱為設計稿要求 */}
      <div className="p-6 sticky bottom-0 bg-white/90 backdrop-blur-md border-t border-gray-50">
        <Link to="/manage-tours" className="block w-full bg-[#00A651] text-white text-center font-bold py-5 rounded-[24px] shadow-lg shadow-green-100 active:scale-95 transition-all">
          Manage Tour Management
        </Link>
      </div>
    </div>
  );
};
export default Home;
